const raw = $input.first().json ?? {};
const viaWebhook = Boolean(raw.body && typeof raw.body === 'object');
const input = viaWebhook ? raw.body : raw;

// Edite somente este token no workflow e use o mesmo valor em
// REPROVACAO_WEBHOOK_TOKEN no EasyPanel.
const WEBHOOK_TOKEN = 'TROQUE_POR_UMA_CHAVE_LONGA';
const GRUPO_ID = 'COLE_O_ID_DO_GRUPO@g.us';
const SESSAO_WAHA = 'whats_junior';

if (viaWebhook) {
  if (!WEBHOOK_TOKEN || WEBHOOK_TOKEN === 'TROQUE_POR_UMA_CHAVE_LONGA') {
    throw new Error('Configure WEBHOOK_TOKEN no node Normalizar entrada e configurar grupo.');
  }
  if (String(input.token || '') !== WEBHOOK_TOKEN) {
    throw new Error('Token inválido para a reprovação enviada pelo painel.');
  }
}

const candidatoId = Number(input.candidato_id);
if (!Number.isInteger(candidatoId) || candidatoId <= 0) {
  throw new Error('candidato_id inválido.');
}
if (!GRUPO_ID || GRUPO_ID.startsWith('COLE_')) {
  throw new Error('Configure o ID real do grupo no node Normalizar entrada e configurar grupo.');
}

const origem = String(input.origem || 'TRIAGEM_AUTOMATICA').trim().toUpperCase();
const permitidas = ['TRIAGEM_EXPERIENCIA_DECLARADA','TRIAGEM_CTPS','TRIAGEM_AUTOMATICA','PAINEL_POS_ENTREVISTA'];
if (!permitidas.includes(origem)) throw new Error(`Origem inválida: ${origem}`);

return [{json:{
  candidato_id:candidatoId,
  origem,
  mensagem_base:String(input.mensagem_base || '').trim(),
  motivo:String(input.motivo || '').trim(),
  observacao:String(input.observacao || '').trim(),
  solicitado_por:String(input.solicitado_por || 'Sistema').trim(),
  finalizar_buffer:Boolean(input.finalizar_buffer),
  grupo_id:GRUPO_ID,
  session:String(input.session || SESSAO_WAHA),
  via_webhook:viaWebhook
}}];

const c=$input.first().json;
if (!c.candidato_id) throw new Error('Candidato não encontrado.');
const origem=String(c.origem||'').toUpperCase();
const etapa=String(c.etapa||'').toUpperCase();
const status=String(c.status||'').toUpperCase();
if (origem==='PAINEL_POS_ENTREVISTA' && !(status==='REPROVADO' && etapa==='REPROVADO_POS_ENTREVISTA')) {
  throw new Error('O candidato não está reprovado após entrevista no painel.');
}
if (origem!=='PAINEL_POS_ENTREVISTA' && !(status==='REPROVADO' && ['REPROVADO_PRE_TRIAGEM','REPROVADO_TRIAGEM'].includes(etapa))) {
  throw new Error('O candidato não está em uma reprovação automática de triagem.');
}
return [{json:{...c,chatId:String(c.telefone||'').replace(/\D/g,'')+'@c.us'}}];

const c=$('Validar origem da reprovação').first().json;
const raw=$input.first().json ?? {};
let code='';
if (typeof raw==='string') code=raw;
else code=String(raw.inviteCode ?? raw.invite_code ?? raw.code ?? raw.value ?? raw.result ?? '').trim();
code=code.replace(/^https?:\/\/chat\.whatsapp\.com\//i,'').trim();
const link=code?`https://chat.whatsapp.com/${code}`:'';
const first=String(c.nome||'').trim().split(/\s+/)[0];
const hi=first?`Olá, ${first}.`:'Olá.';
let base=String(c.mensagem_base||'').trim();
if (!base) {
  if (c.origem==='PAINEL_POS_ENTREVISTA') base=`${hi}\n\nApós a etapa de entrevista, não será possível continuar nesta vaga específica.`;
  else if (c.origem==='TRIAGEM_CTPS') base=`${hi}\n\nApós a análise da sua CTPS, seu perfil não atingiu o requisito desta vaga específica.`;
  else base=`${hi}\n\nPara esta vaga específica, você não atende ao requisito mínimo informado.`;
}
const complemento=link
 ? `\n\nIsso não impede sua participação em outras oportunidades. Divulgamos novas vagas, inclusive oportunidades com critérios diferentes, no grupo abaixo:\n\n${link}\n\nQuando encontrar uma vaga compatível, é só nos chamar novamente no privado.`
 : `\n\nIsso não impede sua participação em futuras oportunidades. Não consegui carregar o link do grupo agora, mas você poderá nos chamar novamente quando encontrar outra vaga.`;
return [{json:{...c,codigo_convite:code,link_convite:link,convite_incluido:Boolean(link),text:(base+complemento).trim()}}];

const c=$input.first().json;
const first=String(c.nome||'').trim().split(/\s+/)[0];
const hi=first?`Olá, ${first}.`:'Olá.';
let base=String(c.mensagem_base||'').trim();
if (!base) {
  base=c.origem==='PAINEL_POS_ENTREVISTA'
    ? `${hi}\n\nApós a etapa de entrevista, não será possível continuar nesta vaga específica.`
    : `${hi}\n\nNeste momento, não será possível continuar nesta vaga específica.`;
}
const complemento='\n\nVocê continuará podendo participar de novas oportunidades. O link do nosso grupo de vagas já foi enviado anteriormente, por isso não vou repeti-lo nesta mensagem.';
return [{json:{...c,codigo_convite:'',link_convite:'',convite_incluido:false,text:(base+complemento).trim()}}];

const sent=$input.first().json ?? {};
let source={};
try { source=$('Montar mensagem com convite').first().json; } catch { source=$('Montar mensagem sem repetir link').first().json; }
return [{json:{...source,mensagem_waha_id:String(sent.id ?? sent.key?.id ?? '')}}];
